output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?season ?seasonLabel WHERE {
  wd:Q29647346 wdt:P179 ?season .
  ?season wdt:P674 wd:Q66560058 .
  OPTIONAL {
    ?season rdfs:label ?seasonLabel .
    FILTER(LANG(?seasonLabel) = 'en')
  }
}

args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?part ?partLabel
WHERE {
  wd:Q29647346 wdt:P5001 ?part .
  ?part wdt:P674 wd:Q66560058 .
  OPTIONAL { ?part rdfs:label ?partLabel . FILTER(LANG(?partLabel) = 'en') }
}
LIMIT 10

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?season ?seasonLabel ?seasonNumber
WHERE {
  wd:Q29647346 wdt:P179 ?season .
  ?season wdt:P123 ?episode .
  ?episode wdt:P674 wd:Q66560058 .
  OPTIONAL { ?season rdfs:label ?seasonLabel . FILTER(LANG(?seasonLabel) = 'en') }
  OPTIONAL { ?season wdt:P1545 ?seasonNumber }
}
LIMIT 10

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?work ?workLabel
WHERE {
  wd:Q66560058 wdt:P1080 ?work .
  OPTIONAL { ?work rdfs:label ?workLabel . FILTER(LANG(?workLabel) = 'en') }
}
LIMIT 5

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?season ?seasonLabel
WHERE {
